"use client";

import Link from "next/link";
import { useMemo, useState } from "react";

type ShowRow = {
  id: string;
  token: string;
  artist: string | null;
  program: string | null;
  show_date: string | null;
  venue: string | null;
  city: string | null;
  start_time: string | null;
  entry_time: string | null;

  contact_name?: string | null;
  contact_email?: string | null;
  contact_phone?: string | null;
  venue_address?: string | null;
  schedule?: string | null;
  technik?: string | null;
  anreise?: string | null;
  unterkunft?: string | null;
  promotion?: string | null;
  general_notes?: string | null;

  internal_status?: string | null;
  billing_status?: string | null;
  next_step?: string | null;
  follow_up_date?: string | null;
  markus_included?: boolean | null;

  show_files?: {
    id: string;
    file_name?: string | null;
    file_type?: string | null;
  }[] | null;
};

export default function AdminClient({
  shows,
  createShowAction,
  deleteShowAction,
  duplicateShowAction,
}: {
  shows: ShowRow[];
  createShowAction: (formData: FormData) => void | Promise<void>;
  deleteShowAction: (formData: FormData) => void | Promise<void>;
  duplicateShowAction: (formData: FormData) => void | Promise<void>;
}) {
  const [query, setQuery] = useState("");
  const [filter, setFilter] = useState("alle");
  const [year, setYear] = useState("alle");
  const [showCreate, setShowCreate] = useState(false);

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const years = Array.from(
    new Set(shows.map((s) => s.show_date?.slice(0, 4)).filter(Boolean))
  ).sort();

  const rows = useMemo(() => {
    return shows.filter((show) => {
      const status = getStatus(show);
      const date = show.show_date ? new Date(show.show_date) : null;
      const isPast = date ? date < today : false;
      const isFuture = date ? date >= today : true;
      const isArchived =
        show.internal_status === "abgeschlossen" ||
        show.internal_status === "archiv";

      const text = [
        show.artist,
        show.program,
        show.venue,
        show.city,
        show.token,
        show.contact_name,
        show.contact_email,
      ]
        .join(" ")
        .toLowerCase();

      const matchesSearch = text.includes(query.toLowerCase());
      const matchesYear = year === "alle" || show.show_date?.startsWith(year);

      const matchesFilter =
        filter === "alle" ||
        (filter === "aktiv" && !isArchived) ||
        (filter === "kommend" && isFuture && !isArchived) ||
        (filter === "entwurf" && !show.show_date) ||
        (filter === "vergangen_offen" && isPast && !isArchived) ||
        (filter === "abrechnung" &&
          isPast &&
          show.billing_status !== "bezahlt") ||
        (filter === "markus" && show.markus_included === true) ||
        (filter === "archiv" && isArchived) ||
        status.key === filter;

      return matchesSearch && matchesYear && matchesFilter;
    });
  }, [shows, query, filter, year]);

  const grouped = groupByMonth(rows);

  return (
    <main className="min-h-screen bg-[#fbf7ef] px-8 py-8 text-zinc-950">
      <div className="mx-auto max-w-6xl space-y-6">
        <header className="relative overflow-hidden rounded-[2rem] bg-[#101014] p-10 text-white shadow-2xl">
          <div className="absolute right-10 top-8 text-6xl text-pink-400">
            ♕
          </div>
          <div className="absolute bottom-8 right-24 text-5xl text-orange-300">
            ★
          </div>
          <div className="absolute right-0 top-0 h-64 w-64 rounded-full bg-pink-500/20 blur-3xl" />
          <div className="absolute bottom-0 left-1/3 h-64 w-64 rounded-full bg-orange-400/20 blur-3xl" />

          <div className="relative flex flex-col gap-6 md:flex-row md:items-end md:justify-between">
            <div>
              <p className="text-sm font-bold uppercase tracking-widest text-white/50">
                primakavi · show admin
              </p>
              <h1 className="mt-4 text-5xl font-black tracking-tight">
                Alle Shows
              </h1>
              <p className="mt-4 text-white/70">
                Shows verwalten, Akten öffnen und Portale verschicken.
              </p>
            </div>

            <button
              type="button"
              onClick={() => setShowCreate((prev) => !prev)}
              className="rounded-3xl bg-gradient-to-r from-pink-400 to-orange-400 px-6 py-4 font-black text-white shadow-xl transition hover:scale-[1.02]"
            >
              Neue Show +
            </button>
          </div>
        </header>

        {showCreate && (
          <section className="rounded-[2rem] bg-white p-6 shadow-xl shadow-black/5">
            <h2 className="text-2xl font-black">Neue Show anlegen</h2>

            <form
              action={createShowAction}
              className="mt-5 grid gap-4 md:grid-cols-4"
            >
              <Input
                name="artist"
                label="Artist"
                defaultValue="Sonja Gründemann"
              />
              <Input
                name="program"
                label="Programm"
                placeholder="Jetzt mal Tacheles"
              />
              <Input name="show_date" label="Datum" type="date" />
              <Input name="venue" label="Location" placeholder="Brakula" />
              <Input name="city" label="Stadt" placeholder="Hamburg" />
              <Input
                name="entry_time"
                label="Einlass"
                placeholder="19:00 Uhr"
              />
              <Input
                name="start_time"
                label="Showbeginn"
                placeholder="20:00 Uhr"
              />

              <button
                type="submit"
                className="self-end rounded-2xl bg-zinc-950 px-5 py-4 font-black text-white shadow-lg"
              >
                Erstellen →
              </button>
            </form>
          </section>
        )}

        <section className="rounded-[2rem] bg-white p-5 shadow-xl shadow-black/5">
          <div className="grid gap-4 lg:grid-cols-[1fr_auto]">
            <input
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Suche nach Location, Stadt, Programm, Kontakt..."
              className="h-14 rounded-2xl border border-zinc-200 bg-[#fbf7ef] px-5 text-sm font-semibold outline-none focus:border-pink-300 focus:ring-4 focus:ring-pink-100"
            />

            <select
              value={year}
              onChange={(e) => setYear(e.target.value)}
              className="h-14 rounded-2xl border border-zinc-200 bg-[#fbf7ef] px-5 text-sm font-black outline-none"
            >
              <option value="alle">Alle Jahre</option>
              {years.map((y) => (
                <option key={y} value={y}>
                  {y}
                </option>
              ))}
            </select>
          </div>

          <div className="mt-4 flex flex-wrap gap-2">
            {[
              ["alle", "Alle"],
              ["aktiv", "Aktiv"],
              ["kommend", "Kommend"],
              ["entwurf", "Entwürfe"],
              ["vergangen_offen", "Vergangen offen"],
              ["abrechnung", "Abrechnung offen"],
              ["markus", "Markus dabei"],
              ["fertig", "Fertig"],
              ["arbeit", "In Arbeit"],
              ["archiv", "Archiv"],
            ].map(([key, label]) => (
              <button
                key={key}
                type="button"
                onClick={() => setFilter(key)}
                className={`rounded-full px-4 py-2 text-sm font-black transition ${
                  filter === key
                    ? "bg-zinc-950 text-white"
                    : "bg-[#fbf7ef] text-zinc-700 hover:bg-[#f5ead9]"
                }`}
              >
                {label}
              </button>
            ))}
          </div>
        </section>

        <section className="rounded-[2rem] bg-white p-5 shadow-xl shadow-black/5">
          {Object.entries(grouped).map(([month, monthShows]) => (
            <div key={month} className="mb-8 last:mb-0">
              <h2 className="mb-4 text-2xl font-black">{month}</h2>

              <div className="space-y-3">
                {monthShows.map((show) => {
                  const status = getStatus(show);
                  const missing = getMissingFields(show);

                  return (
                    <div
                      key={show.id}
                      className="relative rounded-3xl bg-[#fbf7ef] p-5 transition hover:-translate-y-0.5 hover:bg-[#f5ead9]"
                    >
                      <div className="grid gap-4 md:grid-cols-[140px_1fr_170px_250px] md:items-center">
                        <div>
                          <p className="text-lg font-black">
                            {formatDate(show.show_date)}
                          </p>
                          <p className="text-xs font-bold text-zinc-500">
                            {show.start_time || "Uhrzeit offen"}
                          </p>
                        </div>

                        <div>
                          <p className="text-xl font-black">
                            {show.venue || "Location offen"}
                          </p>
                          <p className="text-sm font-semibold text-zinc-500">
                            {show.city || "Ort offen"} ·{" "}
                            {show.program || "Programm offen"}
                          </p>

                          <div className="mt-3 flex flex-wrap gap-2">
                            {show.markus_included && (
                              <span className="rounded-full bg-purple-100 px-3 py-1 text-xs font-black text-purple-700">
                                🎹 Markus dabei
                              </span>
                            )}

                            {missing.slice(0, 3).map((item) => (
                              <span
                                key={item}
                                className="rounded-full bg-white px-3 py-1 text-xs font-black text-zinc-600 shadow-sm"
                              >
                                fehlt: {item}
                              </span>
                            ))}

                            {missing.length > 3 && (
                              <span className="rounded-full bg-white px-3 py-1 text-xs font-black text-zinc-600 shadow-sm">
                                +{missing.length - 3}
                              </span>
                            )}
                          </div>
                        </div>

                        <div>
                          <span
                            className={`rounded-full px-3 py-1 text-xs font-black ${status.className}`}
                          >
                            {status.label}
                          </span>

                          {show.billing_status && (
                            <p className="mt-2 text-xs font-bold text-zinc-500">
                              Abrechnung: {billingLabel(show.billing_status)}
                            </p>
                          )}
                        </div>

                        <div className="relative z-10 flex flex-wrap justify-start gap-2 md:justify-end">
                          <Link
                            href={`/admin/shows/${show.id}`}
                            title="Akte bearbeiten"
                            className="flex h-10 w-10 items-center justify-center rounded-full bg-zinc-950 text-sm font-black text-white transition hover:scale-105"
                          >
                            ✏️
                          </Link>

                          <form action={duplicateShowAction}>
                            <input
                              type="hidden"
                              name="show_id"
                              value={show.id}
                            />
                            <button
                              type="submit"
                              title="Show duplizieren"
                              className="flex h-10 w-10 items-center justify-center rounded-full bg-purple-100 text-sm font-black text-purple-700 transition hover:scale-105"
                            >
                              ⧉
                            </button>
                          </form>

                          <form
                            action={deleteShowAction}
                            onSubmit={(e) => {
                              const ok = window.confirm(
                                `Bist du sicher, dass du die Show "${
                                  show.venue || "ohne Location"
                                }" löschen möchtest?`
                              );
                              if (!ok) e.preventDefault();
                            }}
                          >
                            <input
                              type="hidden"
                              name="show_id"
                              value={show.id}
                            />
                            <button
                              type="submit"
                              title="Show löschen"
                              className="flex h-10 w-10 items-center justify-center rounded-full bg-red-100 text-sm font-black text-red-700 transition hover:scale-105"
                            >
                              🗑️
                            </button>
                          </form>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          ))}

          {rows.length === 0 && (
            <div className="rounded-3xl bg-[#fbf7ef] p-10 text-center">
              <p className="font-black">Keine Shows gefunden.</p>
            </div>
          )}
        </section>
      </div>
    </main>
  );
}

function getMissingFields(show: ShowRow) {
  const missing: string[] = [];

  if (!show.show_date) missing.push("Datum");
  if (!show.venue) missing.push("Location");
  if (!show.city) missing.push("Stadt");
  if (!show.start_time) missing.push("Beginn");
  if (!show.contact_name) missing.push("Kontakt");
  if (!show.contact_email) missing.push("E-Mail");
  if (!show.venue_address) missing.push("Adresse");
  if (!show.technik) missing.push("Technik");

  return missing;
}

function getStatus(show: ShowRow) {
  const date = show.show_date ? new Date(show.show_date) : null;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const isPast = date ? date < today : false;

  if (show.internal_status === "abgeschlossen") {
    return {
      key: "archiv",
      label: "✅ Abgeschlossen",
      className: "bg-emerald-100 text-emerald-700",
    };
  }

  if (show.internal_status === "archiv") {
    return {
      key: "archiv",
      label: "📦 Archiv",
      className: "bg-zinc-200 text-zinc-700",
    };
  }

  if (isPast && show.billing_status !== "bezahlt") {
    return {
      key: "arbeit",
      label: "💸 Abrechnung offen",
      className: "bg-orange-100 text-orange-700",
    };
  }

  const checks = [
    !!show.show_date,
    !!show.contact_name && !!show.contact_email,
    !!show.start_time,
    !!show.technik,
    !!show.venue_address,
    !!show.show_files?.length,
  ];

  const done = checks.filter(Boolean).length;

  if (done === checks.length) {
    return {
      key: "fertig",
      label: "🟢 Fertig",
      className: "bg-emerald-100 text-emerald-700",
    };
  }

  if (done >= checks.length - 2) {
    return {
      key: "fast",
      label: "🟡 Fast fertig",
      className: "bg-amber-100 text-amber-700",
    };
  }

  if (done >= 2) {
    return {
      key: "arbeit",
      label: "🟠 In Arbeit",
      className: "bg-orange-100 text-orange-700",
    };
  }

  return {
    key: "offen",
    label: "🔴 Offen",
    className: "bg-red-100 text-red-700",
  };
}

function billingLabel(value?: string | null) {
  const labels: Record<string, string> = {
    offen: "offen",
    rechnung_geschrieben: "geschrieben",
    rechnung_verschickt: "verschickt",
    bezahlt: "bezahlt",
  };

  return labels[value || ""] || value || "offen";
}

function groupByMonth(shows: ShowRow[]) {
  return shows.reduce<Record<string, ShowRow[]>>((acc, show) => {
    const label = monthLabel(show.show_date);
    acc[label] ||= [];
    acc[label].push(show);
    return acc;
  }, {});
}

function monthLabel(date?: string | null) {
  if (!date) return "Ohne Datum";

  const d = new Date(date);
  if (Number.isNaN(d.getTime())) return "Ohne Datum";

  return d.toLocaleDateString("de-DE", {
    month: "long",
    year: "numeric",
  });
}

function Input({
  name,
  label,
  type = "text",
  placeholder,
  defaultValue,
}: {
  name: string;
  label: string;
  type?: string;
  placeholder?: string;
  defaultValue?: string;
}) {
  return (
    <label className="grid gap-2 text-xs font-black text-zinc-700">
      {label}
      <input
        name={name}
        type={type}
        placeholder={placeholder}
        defaultValue={defaultValue}
        className="h-14 rounded-2xl border border-zinc-200 bg-[#fbf7ef] px-4 text-sm font-semibold outline-none focus:border-pink-300 focus:ring-4 focus:ring-pink-100"
      />
    </label>
  );
}

function formatDate(date?: string | null) {
  if (!date) return "Datum offen";

  const d = new Date(date);
  if (Number.isNaN(d.getTime())) return date;

  return d.toLocaleDateString("de-DE", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  });
}